join public.teams team on team.fifa_code = seed.fifa_team_code
on conflict (fifa_team_code, squad_number) do update set
  team_id = excluded.team_id, team_name = excluded.team_name, position = excluded.position,
  player_name = excluded.player_name, first_names = excluded.first_names,
  last_names = excluded.last_names, shirt_name = excluded.shirt_name,
  date_of_birth = excluded.date_of_birth, club = excluded.club, height_cm = excluded.height_cm,
  is_active = true, updated_at = now();

select count(*) as player_count from public.players;
select fifa_team_code, count(*) from public.players group by fifa_team_code order by fifa_team_code;
